### 3. IndexedDB Storage Service (JavaScript Interop)

Create `SiteInspector.Client/wwwroot/js/indexedDb.js`:
```javascript
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(JSON.parse(item));
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedCount: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(request.result ? request.result.length : 0);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};
```

### 4. C# Storage Service

Create `SiteInspector.Client/Services/LocalStorageService.cs`:
```csharp
using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class LocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    // Sites
    public async Task SaveSiteAsync(Site site)
    {
        var json = JsonSerializer.Serialize(site, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "sites", json);
    }

    public async Task<List<Site>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbStorage.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<Site>>(json, JsonOptions) ?? new();
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbStorage.getItem", "sites", id);
        return json is null ? null : JsonSerializer.Deserialize<Site>(json, JsonOptions);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "inspections", json);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbStorage.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("indexedDbStorage.getItemsByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbStorage.getItem", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", "inspections", id);
    }

    public async Task<int> GetUnsyncedCountAsync()
    {
        return await _js.InvokeAsync<int>("indexedDbStorage.getUnsyncedCount");
    }
}
```

### 5. Sync Service

Create `SiteInspector.Client/Services/SyncService.cs`:
```csharp
using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private Timer? _syncTimer;
    private bool _isSyncing;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = new();

    public SyncService(LocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public void StartPeriodicSync(TimeSpan interval)
    {
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.Zero, interval);
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing) return;
        _isSyncing = true;

        try
        {
            var isOnline = await CheckConnectivityAsync();
            CurrentStatus.IsOnline = isOnline;

            if (!isOnline)
            {
                CurrentStatus.PendingInspections = await _storage.GetUnsyncedCountAsync();
                NotifyStatusChanged();
                return;
            }

            CurrentStatus.IsSyncing = true;
            NotifyStatusChanged();

            var inspections = await _storage.GetAllInspectionsAsync();
            var unsynced = inspections.Where(i => !i.IsSynced && i.Status == InspectionStatus.Completed).ToList();

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _storage.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    // Individual sync failure — continue with others
                }
            }

            CurrentStatus.LastSyncedAt = DateTime.UtcNow;
            CurrentStatus.PendingInspections = await _storage.GetUnsyncedCountAsync();
        }
        catch
        {
            // Sync attempt failed — will retry next interval
        }
        finally
        {
            _isSyncing = false;
            CurrentStatus.IsSyncing = false;
            NotifyStatusChanged();
        }
    }

    private async Task<bool> CheckConnectivityAsync()
    {
        try
        {
            var response = await _http.GetAsync("api/health");
            return response.IsSuccessStatusCode;
        }
        catch
        {
            return false;
        }
    }

    private void NotifyStatusChanged() => OnSyncStatusChanged?.Invoke(CurrentStatus);

    public void Dispose()
    {
        _syncTimer?.Dispose();
    }
}
```

