app.MapPost("api/inspections", (Inspection inspection) =>
{
    // In production, persist to a database. For now, accept and acknowledge.
    return Results.Ok(new { id = inspection.Id, synced = true });
});

app.MapGet("api/inspections", () =>
{
    // Placeholder for server-side inspection retrieval
    return Results.Ok(Array.Empty<Inspection>());
});

app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

app.Run();
