### 3. IndexedDB Storage Service (JavaScript Interop)

Create `SiteInspector.Client/wwwroot/js/indexedDb.js`:
```javascript
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(JSON.parse(item));
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedCount: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(request.result ? request.result.length : 0);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};
