@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@using SiteInspector.Client.Shared
@inject LocalStorageService Storage
@inject SyncService Sync

<PageTitle>Site Inspector</PageTitle>

<div class="app-header">
    <h1>🏗️ Site Inspector</h1>
    <SyncIndicator />
</div>

<div class="action-bar">
    <button class="btn btn-primary btn-lg w-100" @onclick="ShowAddSite">
        ＋ Add Construction Site
    </button>
</div>

@if (_showAddSite)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Site</h5>
            <div class="mb-2">
                <input type="text" class="form-control form-control-lg" placeholder="Site name" @bind="_newSiteName" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control" placeholder="Address (optional)" @bind="_newSiteAddress" />
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-success flex-grow-1" @onclick="AddSite">Save</button>
                <button class="btn btn-outline-secondary" @onclick="CancelAddSite">Cancel</button>
            </div>
        </div>
    </div>
}

@if (_sites.Count == 0 && !_showAddSite)
{
    <div class="empty-state">
        <p>No construction sites yet.</p>
        <p class="text-muted">Tap "Add Construction Site" to get started.</p>
    </div>
}

<div class="site-list">
    @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
    {
        <a href="/site/@site.Id" class="site-card">
            <div class="site-card-content">
                <h5>@site.Name</h5>
                @if (!string.IsNullOrEmpty(site.Address))
                {
                    <p class="text-muted mb-0">@site.Address</p>
                }
            </div>
            <span class="chevron">›</span>
        </a>
    }
</div>

@code {
    private List<Site> _sites = new();
    private bool _showAddSite;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _sites = await Storage.GetAllSitesAsync();
            Sync.StartPeriodicSync(TimeSpan.FromSeconds(30));
            StateHasChanged();
        }
    }

    private void ShowAddSite() => _showAddSite = true;
    private void CancelAddSite() { _showAddSite = false; _newSiteName = ""; _newSiteAddress = ""; }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new Site { Name = _newSiteName.Trim(), Address = _newSiteAddress.Trim() };
        await Storage.SaveSiteAsync(site);
        _sites.Add(site);
        _showAddSite = false;
        _newSiteName = "";
        _newSiteAddress = "";
    }
}

