@page "/site/{SiteId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Details</PageTitle>

<div class="app-header">
    <a href="/" class="back-link">← Back</a>
    <h1>@_site?.Name</h1>
</div>

<div class="action-bar">
    <button class="btn btn-primary btn-lg w-100" @onclick="StartNewInspection">
        📋 Start New Inspection
    </button>
</div>

@if (_inspections.Count == 0)
{
    <div class="empty-state">
        <p>No inspections yet for this site.</p>
    </div>
}

<div class="inspection-list">
    @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectionDate))
    {
        <a href="/inspection/@inspection.Id" class="inspection-card">
            <div class="inspection-card-content">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="mb-0">@inspection.InspectionDate.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</h6>
                    <span class="badge @GetStatusBadgeClass(inspection)">@inspection.Status</span>
                </div>
                <div class="inspection-meta">
                    <span>@GetCompletedCount(inspection)/@inspection.ChecklistItems.Count items</span>
                    @if (inspection.Photos.Count > 0)
                    {
                        <span>📷 @inspection.Photos.Count</span>
                    }
                    @if (inspection.IsSynced)
                    {
                        <span class="synced-badge">✓ Synced</span>
                    }
                    else
                    {
                        <span class="pending-badge">⏳ Pending</span>
                    }
                </div>
            </div>
            <span class="chevron">›</span>
        </a>
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _site = await Storage.GetSiteAsync(SiteId);
            _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
            StateHasChanged();
        }
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            ChecklistItems = ChecklistTemplates.GetDefaultSafetyChecklist()
        };
        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private int GetCompletedCount(Inspection i) =>
        i.ChecklistItems.Count(c => c.Result != ChecklistResult.NotInspected);

    private string GetStatusBadgeClass(Inspection i) =>
        i.Status == InspectionStatus.Completed ? "bg-success" : "bg-warning text-dark";
}

@page "/inspection/{InspectionId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject LocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Inspection</PageTitle>

<div class="app-header">
    <a href="@BackUrl" class="back-link">← Back</a>
    <h1>Inspection</h1>
</div>

<div class="tab-bar">
    <button class="tab-btn @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
        ✓ Checklist
    </button>
    <button class="tab-btn @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
        📷 Photos (@(_inspection?.Photos.Count ?? 0))
    </button>
    <button class="tab-btn @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
        📝 Notes
    </button>
</div>

@if (_inspection is not null)
{
    @if (_activeTab == "checklist")
    {
        <div class="checklist-container">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h6 class="category-header">@category.Key</h6>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <div class="checklist-description">@item.Description</div>
                            <div class="checklist-buttons">
                                <button class="result-btn pass @(item.Result == ChecklistResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, ChecklistResult.Pass)">✓</button>
                                <button class="result-btn fail @(item.Result == ChecklistResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, ChecklistResult.Fail)">✗</button>
                                <button class="result-btn na @(item.Result == ChecklistResult.NotApplicable ? "selected" : "")"
                                        @onclick="() => SetResult(item, ChecklistResult.NotApplicable)">N/A</button>
                            </div>
                            @if (item.Result == ChecklistResult.Fail)
                            {
                                <input type="text" class="form-control form-control-sm mt-1"
                                       placeholder="Note about failure..."
                                       value="@item.Notes"
                                       @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? "")" />
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-container">
            <div class="mb-3">
                <label class="btn btn-outline-primary btn-lg w-100">
                    📷 Take / Add Photo
                    <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" class="d-none" />
                </label>
            </div>

            @if (_inspection.Photos.Count == 0)
            {
                <div class="empty-state">
                    <p>No photos yet. Tap above to add.</p>
                </div>
            }

            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                {
                    <div class="photo-card">
                        <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                        <div class="photo-caption">
                            <input type="text" class="form-control form-control-sm"
                                   placeholder="Add caption..."
                                   value="@photo.Caption"
                                   @onchange="(e) => SetPhotoCaption(photo, e.Value?.ToString() ?? "")" />
                        </div>
                    </div>
                }
            </div>
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-container">
            <textarea class="form-control" rows="8"
                      placeholder="General inspection notes..."
                      @bind="_inspection.Notes"
                      @bind:after="SaveAsync"></textarea>
        </div>
    }

    <div class="bottom-actions">
        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <button class="btn btn-success btn-lg w-100" @onclick="CompleteInspection">
                ✓ Complete Inspection
            </button>
        }
        else
        {
            <div class="alert alert-success text-center mb-0">
                ✓ Inspection completed
                @if (_inspection.IsSynced)
                {
                    <span>and synced</span>
                }
            </div>
        }
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string BackUrl => _inspection is not null ? $"/site/{_inspection.SiteId}" : "/";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _inspection = await Storage.GetInspectionAsync(InspectionId);
            StateHasChanged();
        }
    }

    private async Task SetResult(ChecklistItem item, ChecklistResult result)
    {
        item.Result = result;
        await SaveAsync();
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveAsync();
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue;

            using var stream = file.OpenReadStream(10 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            _inspection!.Photos.Add(new PhotoRecord
            {
                FileName = file.Name,
                Base64Data = base64
            });
        }
        await SaveAsync();
    }

    private async Task SetPhotoCaption(PhotoRecord photo, string caption)
    {
        photo.Caption = caption;
        await SaveAsync();
    }

    private async Task CompleteInspection()
    {
        _inspection!.Status = InspectionStatus.Completed;
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_inspection is not null)
        {
            await Storage.SaveInspectionAsync(_inspection);
        }
    }

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        ChecklistResult.Pass => "item-pass",
        ChecklistResult.Fail => "item-fail",
        ChecklistResult.NotApplicable => "item-na",
        _ => ""
    };
}

@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@implements IDisposable
@inject SyncService Sync

<div class="sync-indicator @(_status.IsOnline ? "online" : "offline")">
    @if (_status.IsSyncing)
    {
        <span class="sync-icon spinning">↻</span>
    }
    else if (_status.IsOnline)
    {
        <span class="sync-icon">●</span>
    }
    else
    {
        <span class="sync-icon">○</span>
    }
    @if (_status.PendingInspections > 0)
    {
        <span class="pending-count">@_status.PendingInspections pending</span>
    }
</div>

@code {
    private SyncStatus _status = new();

    protected override void OnInitialized()
    {
        Sync.OnSyncStatusChanged += HandleStatusChanged;
        _status = Sync.CurrentStatus;
    }

    private void HandleStatusChanged(SyncStatus status)
    {
        _status = status;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= HandleStatusChanged;
    }
}

