+    {
+        <span class="sync-icon spinning">↻</span>
+    }
+    else if (_status.IsOnline)
+    {
+        <span class="sync-icon">●</span>
+    }
+    else
+    {
+        <span class="sync-icon">○</span>
+    }
+    @if (_status.PendingInspections > 0)
+    {
+        <span class="pending-count">@_status.PendingInspections pending</span>
+    }
+</div>
+
