    padding: 16px;
    text-decoration: none;
    color: inherit;
    box-shadow: var(--shadow);
    min-height: 64px;
    transition: transform 0.1s;
}

.site-card:active, .inspection-card:active {
    transform: scale(0.98);
}

.site-card-content h5, .inspection-card-content h6 {
    margin: 0;
    color: var(--gray-800);
}

.chevron {
    font-size: 1.5rem;
    color: var(--gray-500);
    font-weight: 300;
}

.inspection-meta {
    display: flex;
    gap: 12px;
    margin-top: 6px;
    font-size: 0.85rem;
    color: var(--gray-500);
}

.synced-badge { color: var(--success); }
.pending-badge { color: var(--warning); }

/* Tab bar */
.tab-bar {
    display: flex;
    gap: 4px;
    margin-bottom: 16px;
    background: var(--gray-200);
    border-radius: var(--radius);
    padding: 4px;
}

.tab-btn {
    flex: 1;
    border: none;
    background: transparent;
    padding: 12px 8px;
    border-radius: 8px;
    font-size: 0.9rem;
    font-weight: 500;
    color: var(--gray-500);
    min-height: 48px;
    cursor: pointer;
}

.tab-btn.active {
    background: white;
    color: var(--gray-800);
    box-shadow: var(--shadow);
}

/* Checklist */
.checklist-container {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.checklist-category {
    background: white;
    border-radius: var(--radius);
    padding: 12px;
    box-shadow: var(--shadow);
}

.category-header {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--primary);
    font-weight: 700;
    margin-bottom: 8px;
    padding-bottom: 8px;
    border-bottom: 1px solid var(--gray-200);
}

.checklist-item {
    padding: 10px 0;
    border-bottom: 1px solid var(--gray-100);
}

.checklist-item:last-child {
    border-bottom: none;
    padding-bottom: 0;
}

.checklist-description {
    font-size: 0.95rem;
    margin-bottom: 8px;
    color: var(--gray-800);
}

.checklist-buttons {
    display: flex;
    gap: 8px;
}

.result-btn {
    min-width: 48px;
    min-height: 48px;
    border: 2px solid var(--gray-200);
    border-radius: 8px;
    background: white;
    font-size: 1.2rem;
    font-weight: 700;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s;
}

.result-btn.pass { color: var(--success); }
.result-btn.fail { color: var(--danger); }
.result-btn.na { color: var(--gray-500); font-size: 0.75rem; }

.result-btn.pass.selected {
    background: var(--success);
    color: white;
    border-color: var(--success);
}

.result-btn.fail.selected {
    background: var(--danger);
    color: white;
    border-color: var(--danger);
}

.result-btn.na.selected {
    background: var(--gray-500);
    color: white;
    border-color: var(--gray-500);
}

.item-pass { border-left: 3px solid var(--success); padding-left: 10px; }
.item-fail { border-left: 3px solid var(--danger); padding-left: 10px; }
.item-na { border-left: 3px solid var(--gray-500); padding-left: 10px; opacity: 0.7; }

/* Photos */
.photos-container {
    padding-bottom: 16px;
}

.photo-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
}

.photo-card {
    border-radius: var(--radius);
    overflow: hidden;
    background: white;
    box-shadow: var(--shadow);
}

.photo-card img {
    width: 100%;
    height: 150px;
    object-fit: cover;
}

.photo-caption {
    padding: 8px;
}

/* Notes */
.notes-container {
    background: white;
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
}

.notes-container textarea {
    border: none;
    resize: vertical;
    font-size: 1rem;
    min-height: 200px;
}

.notes-container textarea:focus {
    box-shadow: none;
    border: none;
}

/* Bottom actions */
.bottom-actions {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    padding: 12px 16px;
    background: white;
    box-shadow: 0 -2px 8px rgba(0,0,0,0.08);
    z-index: 100;
}

.bottom-actions .btn {
    min-height: 56px;
    font-size: 1.1rem;
    font-weight: 600;
    border-radius: var(--radius);
}

/* Sync indicator */
.sync-indicator {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 0.8rem;
    padding: 6px 10px;
    border-radius: 20px;
    background: white;
    box-shadow: var(--shadow);
}

.sync-indicator.online .sync-icon { color: var(--success); }
.sync-indicator.offline .sync-icon { color: var(--gray-500); }
.pending-count { color: var(--warning); font-weight: 600; }

.sync-icon.spinning {
    animation: spin 1s linear infinite;
}

@keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

/* Cards */
.card {
    border: none;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
}

/* Form controls */
.form-control {
    border-radius: 8px;
    min-height: 48px;
    font-size: 1rem;
}

.form-control-lg {
    min-height: 56px;
    font-size: 1.1rem;
}

.form-control-sm {
    min-height: 36px;
    font-size: 0.85rem;
}

/* Buttons */
.btn {
    border-radius: 8px;
    min-height: 48px;
    font-weight: 500;
}

.btn-primary {
    background: var(--primary);
    border-color: var(--primary);
}

.btn-primary:hover, .btn-primary:active {
    background: var(--primary-dark);
    border-color: var(--primary-dark);
}

.btn-success {
    background: var(--success);
    border-color: var(--success);
}

/* Badge */
.badge {
    font-size: 0.7rem;
    padding: 4px 8px;
    border-radius: 6px;
}

/* Responsive */
@media (min-width: 768px) {
    .app-container {
        padding: 0 24px 80px;
    }

    .photo-grid {
        grid-template-columns: 1fr 1fr 1fr;
    }
}
EOF

